SELECT plot_code, location
FROM plots
WHERE elevation > 200;

SELECT AVG(ann_def_mm) AS average_annual_deficit
FROM water_deficits
WHERE water_stress_index > 50;

SELECT COUNT(fire_id) AS fire_event_count
FROM fire_events
WHERE plot_id = 1;

SELECT DISTINCT plot_id
FROM fire_events
ORDER BY fire_year, plot_id;

SELECT COUNT(*) AS plot_count
FROM plots
WHERE location = 'Forest Reserve';

SELECT DISTINCT fire_year
FROM fire_events
WHERE fire_cause = 'Lightning';

SELECT AVG(ann_def_mm) AS avg_annual_deficit, COUNT(plot_id) AS number_of_plots
FROM water_deficits
WHERE year = 2009;

SELECT plot_code
FROM plots
WHERE elevation = (SELECT MAX(elevation) FROM plots);
